import model.Hotel;
import model.LayoutLoader;
import ui.HotelPanel;
import model.Simulator;

import javax.swing.*;
import java.io.File;
import java.util.Arrays;

public class main {

    private static HotelPanel hotelPanel;
    private static JComboBox<String> layoutDropdown;
    private static JLabel statusLabel;
    private static Simulator simulator;

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> {
            try {
                JFrame frame = new JFrame("Hotel Simulator");
                frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

                JPanel controlPanel = new JPanel();
                controlPanel.add(new JLabel("Selecteer layout: "));

                // layouts ophalen
                String[] layouts = getAvailableLayouts();

                layoutDropdown = new JComboBox<>(layouts);
                controlPanel.add(layoutDropdown);

                // load knop
                JButton loadButton = new JButton("Laden");
                loadButton.addActionListener(e -> loadLayout());
                controlPanel.add(loadButton);

                // pause knop
                JButton pauseButton = new JButton("Pause");
                controlPanel.add(pauseButton);

                pauseButton.addActionListener(e -> {
                    if (simulator.isRunning()) {
                        simulator.pause();
                        pauseButton.setText("Resume");
                        statusLabel.setText("Simulatie gepauzeerd");
                    } else {
                        simulator.start();
                        pauseButton.setText("Pause");
                        statusLabel.setText("Simulatie actief");
                    }
                });

                // status label
                statusLabel = new JLabel("Hotel laden...");
                controlPanel.add(statusLabel);

                // eerste layout laden
                Hotel hotel = LayoutLoader.laadLayout("layouts/" + layouts[0]);
                hotelPanel = new HotelPanel(hotel);

                //  simulator hier maken (BELANGRIJK)
                simulator = new Simulator(hotelPanel);
                simulator.start();

                statusLabel.setText("Hotel geladen: " + layouts[0]);

                frame.add(controlPanel, "North");
                frame.add(hotelPanel, "Center");

                frame.pack();
                frame.setLocationRelativeTo(null);
                frame.setVisible(true);

                //  HTE ticks
                new Timer(500, e -> simulator.tick()).start();

            } catch (Exception e) {
                System.out.println("Fout: " + e.getMessage());
                e.printStackTrace();
            }
        });
    }

    private static String[] getAvailableLayouts() {
        File layoutDir = new File("layouts");
        String[] layouts = layoutDir.list((dir, name) -> name.endsWith(".json"));

        if (layouts == null || layouts.length == 0) {
            throw new RuntimeException("Geen layout bestanden gevonden");
        }

        Arrays.sort(layouts);
        return layouts;
    }

    private static void loadLayout() {
        try {
            String selectedLayout = (String) layoutDropdown.getSelectedItem();

            Hotel newHotel = LayoutLoader.laadLayout("layouts/" + selectedLayout);
            hotelPanel.setHotel(newHotel);

            //  simulator resetten
            simulator = new Simulator(hotelPanel);
            simulator.start();

            statusLabel.setText("Hotel geladen: " + selectedLayout);

        } catch (Exception e) {
            statusLabel.setText("Fout: " + e.getMessage());
        }
    }
}

import model.Hotel;
import model.LayoutLoader;
import model.Gast;
import ui.HotelPanel;
import model.Simulator;

import javax.swing.*;
import java.io.File;
import java.util.Arrays;

public class main {

    private static HotelPanel hotelPanel;
    private static JComboBox<String> layoutDropdown;
    private static JLabel statusLabel;
    private static Simulator simulator;

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> {
            try {
                JFrame frame = new JFrame("Hotel Simulator");
                frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

                JPanel controlPanel = new JPanel();
                controlPanel.add(new JLabel("Selecteer layout: "));

                // layouts ophalen
                String[] layouts = getAvailableLayouts();

                layoutDropdown = new JComboBox<>(layouts);
                controlPanel.add(layoutDropdown);

                // load knop
                JButton loadButton = new JButton("Laden");
                loadButton.addActionListener(e -> loadLayout());
                controlPanel.add(loadButton);

                // pause knop (declare first, configure later)
                JButton pauseButton = new JButton("Pause");
                pauseButton.setEnabled(false);

                // Start knop
                JButton startButton = new JButton("Start");
                startButton.addActionListener(e -> {
                    if (!simulator.isRunning()) {
                        simulator.start();
                        startButton.setEnabled(false);
                        pauseButton.setEnabled(true);
                        statusLabel.setText("Simulatie actief");
                    }
                });
                controlPanel.add(startButton);

                // Configure pause button
                pauseButton.addActionListener(e -> {
                    if (simulator.isRunning()) {
                        simulator.pause();
                        pauseButton.setText("Resume");
                        startButton.setEnabled(true);
                        statusLabel.setText("Simulatie gepauzeerd");
                    } else {
                        simulator.start();
                        pauseButton.setText("Pause");
                        startButton.setEnabled(false);
                        statusLabel.setText("Simulatie actief");
                    }
                });
                controlPanel.add(pauseButton);

                // status label
                statusLabel = new JLabel("Hotel laden...");
                controlPanel.add(statusLabel);

                // eerste layout laden
                Hotel hotel = LayoutLoader.laadLayout("layouts/" + layouts[0]);
                hotelPanel = new HotelPanel(hotel);

                // Voeg test gasten toe
                addTestGuests(hotel);

                //  simulator hier maken (BELANGRIJK)
                simulator = new Simulator(hotel, hotelPanel);
                simulator.pause(); // Start in paused state

                statusLabel.setText("Hotel geladen: " + layouts[0] + " (Klik 'Start' om de simulatie te beginnen)");

                frame.add(controlPanel, "North");
                frame.add(hotelPanel, "Center");

                frame.pack();
                frame.setLocationRelativeTo(null);
                frame.setVisible(true);

                //  HTE ticks
                new Timer(500, e -> simulator.tick()).start();

            } catch (Exception e) {
                System.out.println("Fout: " + e.getMessage());
                e.printStackTrace();
            }
        });
    }

    private static String[] getAvailableLayouts() {
        File layoutDir = new File("layouts");
        String[] layouts = layoutDir.list((dir, name) -> name.endsWith(".json"));

        if (layouts == null || layouts.length == 0) {
            throw new RuntimeException("Geen layout bestanden gevonden");
        }

        Arrays.sort(layouts);
        return layouts;
    }

    private static void loadLayout() {
        try {
            String selectedLayout = (String) layoutDropdown.getSelectedItem();

            Hotel newHotel = LayoutLoader.laadLayout("layouts/" + selectedLayout);
            hotelPanel.setHotel(newHotel);

            // Voeg test gasten toe aan het nieuwe hotel
            addTestGuests(newHotel);

            //  simulator resetten op paused state
            simulator = new Simulator(newHotel, hotelPanel);
            simulator.pause();

            statusLabel.setText("Hotel geladen: " + selectedLayout + " (Klik 'Start' om de simulatie te beginnen)");

        } catch (Exception e) {
            statusLabel.setText("Fout: " + e.getMessage());
        }
    }

    private static void addTestGuests(Hotel hotel) {
        // Voeg enkele test gasten toe
        model.Gast gast1 = new model.Gast("Alice", 2, 2);
        gast1.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        hotel.addPersoon(gast1);

        model.Gast gast2 = new model.Gast("Bob", 3, 3);
        gast2.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        hotel.addPersoon(gast2);

        model.Gast gast3 = new model.Gast("Charlie", 1, 1);
        gast3.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        hotel.addPersoon(gast3);
    }
}

package model;

import java.awt.Color;
import java.util.Random;

/**
 * Gast - Een gast die verblijft in het hotel.
 * Gasten hebben een positie op het grid en bewegen door het hotel.
 */
public class Gast extends Persoon {

    private static final Random RANDOM = new Random();

    // Positie van de gast (x, y op het grid)
    private int x;
    private int y;

    // Destinatie waar de gast naar toe wil
    private int destX;
    private int destY;

    // Kleur van de gast
    private Color kleur;

    // Huidige status/activiteit van de gast
    private String status; // bijv. "in_kamer", "naar_restaurant", "in_lobby"

    // Grid boundaries voor random movement
    private int maxX = 10;
    private int maxY = 10;

    /**
     * Constructor voor een nieuwe gast.
     * @param naam De naam van de gast
     * @param startX De X-positie waar de gast start
     * @param startY De Y-positie waar de gast start
     */
    public Gast(String naam, int startX, int startY) {
        super(naam, "Gast");
        this.x = startX;
        this.y = startY;
        this.kleur = generateRandomColor();
        this.status = "in_lobby";
        // Eerste willekeurige destinatie
        chooseRandomDestination();
    }

    /**
     * Genereer een willekeurige, levendige kleur voor de gast.
     */
    private static Color generateRandomColor() {
        int r = 100 + RANDOM.nextInt(156); // 100-255
        int g = 100 + RANDOM.nextInt(156); // 100-255
        int b = 100 + RANDOM.nextInt(156); // 100-255
        return new Color(r, g, b);
    }

    /**
     * Kies een willekeurig doel op het grid.
     */
    private void chooseRandomDestination() {
        this.destX = RANDOM.nextInt(maxX);
        this.destY = RANDOM.nextInt(maxY);
    }

    /**
     * Stel het grid maximum in voor random movement.
     */
    public void setGridBounds(int maxX, int maxY) {
        this.maxX = maxX;
        this.maxY = maxY;
    }

    // Getters en Setters voor positie
    public int getX() { return x; }
    public int getY() { return y; }

    public void setX(int x) { this.x = x; }
    public void setY(int y) { this.y = y; }

    // Getters en Setters voor destinatie
    public int getDestX() { return destX; }
    public int getDestY() { return destY; }

    public void setDestX(int destX) { this.destX = destX; }
    public void setDestY(int destY) { this.destY = destY; }

    // Getters voor kleur
    public Color getKleur() { return kleur; }

    // Getters en Setters voor status
    public String getStatus() { return status; }
    public void setStatus(String status) { this.status = status; }

    /**
     * Beweeg de gast naar de destinatie (simpele AI).
     * Elke tick beweegt de gast een stap in de richting van de destinatie.
     * Wanneer het doel bereikt is, kiest de gast automatisch een nieuw willekeurig doel.
     */
    public void update() {
        // Controleer of we op de destinatie zijn
        if (x == destX && y == destY) {
            // Kies een nieuw doel en begin meteen naar toe te lopen
            chooseRandomDestination();
        }

        // Beweeg een stap dichter naar de destinatie
        if (x < destX) x++;
        else if (x > destX) x--;

        if (y < destY) y++;
        else if (y > destY) y--;
    }

    @Override
    public String toString() {
        return "Gast{" +
                "id=" + getId() +
                ", naam='" + getNaam() + '\'' +
                ", pos=(" + x + "," + y + ")" +
                ", dest=(" + destX + "," + destY + ")" +
                ", status='" + status + '\'' +
                '}';
    }
}

package model;

import java.util.List;

/**
 * Stelt een hotel voor met een 2D grid en een lijst van ruimtes (areas).
 * Wordt aangemaakt door de LayoutLoader op basis van een JSON bestand.
 */
public class Hotel {

    // Het 2D grid met ruimtetypes als strings (bijv. "L", "F", "T")
    private String[][] grid;

    // Breedte en hoogte van het grid in vakjes
    private int breedte;
    private int hoogte;

    // Lijst van alle ruimtes (kamers, faciliteiten, lobby etc.)
    private List<Area> areas;

    /**
     * Maakt een nieuw Hotel aan met een grid en lijst van areas.
     */
    public Hotel(String[][] grid, int breedte, int hoogte, List<Area> areas) {
        this.grid = grid;
        this.breedte = breedte;
        this.hoogte = hoogte;
        this.areas = areas;
    }

    // Geeft het 2D grid terug
    public String[][] getGrid() { return grid; }

    // Geeft de breedte van het grid terug
    public int getBreedte() { return breedte; }

    // Geeft de hoogte van het grid terug
    public int getHoogte() { return hoogte; }

    // Geeft de lijst van alle areas terug
    public List<Area> getAreas() { return areas; }
}

package model;

import java.util.ArrayList;
import java.util.List;

/**
 * Stelt een hotel voor met een 2D grid en een lijst van ruimtes (areas).
 * Wordt aangemaakt door de LayoutLoader op basis van een JSON bestand.
 */
public class Hotel {

    // Het 2D grid met ruimtetypes als strings (bijv. "L", "F", "T")
    private String[][] grid;

    // Breedte en hoogte van het grid in vakjes
    private int breedte;
    private int hoogte;

    // Lijst van alle ruimtes (kamers, faciliteiten, lobby etc.)
    private List<Area> areas;

    // Lijst van alle personen in het hotel
    private List<Persoon> personen;

    /**
     * Maakt een nieuw Hotel aan met een grid en lijst van areas.
     */
    public Hotel(String[][] grid, int breedte, int hoogte, List<Area> areas) {
        this.grid = grid;
        this.breedte = breedte;
        this.hoogte = hoogte;
        this.areas = areas;
        this.personen = new ArrayList<>();
    }

    // Geeft het 2D grid terug
    public String[][] getGrid() { return grid; }

    // Geeft de breedte van het grid terug
    public int getBreedte() { return breedte; }

    // Geeft de hoogte van het grid terug
    public int getHoogte() { return hoogte; }

    // Geeft de lijst van alle areas terug
    public List<Area> getAreas() { return areas; }

    // Geeft de lijst van personen terug
    public List<Persoon> getPersonen() { return personen; }

    // Voeg een persoon toe aan het hotel
    public void addPersoon(Persoon persoon) {
        personen.add(persoon);
    }
}

package model;

import ui.HotelPanel;

public class Simulator {

    private boolean running;
    private HotelPanel hotelPanel;

    public Simulator(HotelPanel hotelPanel) {
        this.hotelPanel = hotelPanel;
        this.running = false;
    }

    public void start() {
        running = true;
        hotelPanel.setRunning(true);
    }

    public void pause() {
        running = false;
        hotelPanel.setRunning(false);
    }

    public boolean isRunning() {
        return running;
    }

    public void tick() {
        if (!running) return;

        //  BELANGRIJK: dit triggert jouw paintComponent()
        hotelPanel.repaint();
    }
}

package model;

import ui.HotelPanel;

public class Simulator {

    private boolean running;
    private HotelPanel hotelPanel;
    private Hotel hotel;

    public Simulator(Hotel hotel, HotelPanel hotelPanel) {
        this.hotel = hotel;
        this.hotelPanel = hotelPanel;
        this.running = false;
    }

    public void start() {
        running = true;
        hotelPanel.setRunning(true);
    }

    public void pause() {
        running = false;
        hotelPanel.setRunning(false);
    }

    public boolean isRunning() {
        return running;
    }

    public void tick() {
        if (!running) return;

        // Update all personen (guests move according to their logic)
        for (Persoon persoon : hotel.getPersonen()) {
            if (persoon instanceof Gast) {
                ((Gast) persoon).update();
            }
        }

        //  BELANGRIJK: dit triggert jouw paintComponent()
        hotelPanel.repaint();
    }
}

package ui;

import model.Area;
import model.Hotel;
import javax.swing.*;
import java.awt.*;
import java.util.List;

/**
 * Dit paneel is verantwoordelijk voor het visueel weergeven van het hotel.
 */
public class HotelPanel extends JPanel {

    private Hotel hotel;

    private final int VAKJE_GROOTTE = 50;

    //  NIEUW: status van simulatie (optioneel)
    private boolean running = true;

    public HotelPanel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
    }

    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
        repaint();
    }

    //  NIEUW: Simulator kan dit gebruiken
    public void setRunning(boolean running) {
        this.running = running;
    }

    private void updateDimensions() {
        if (hotel == null) return;

        int breedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        this.setPreferredSize(new Dimension(breedte, hoogte));
        revalidate(); //  belangrijk voor UI refresh
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        if (hotel == null) return;

        // Achtergrond (vloer)
        g.setColor(new Color(220, 220, 220));
        g.fillRect(0, 0, hotel.getBreedte() * VAKJE_GROOTTE, hotel.getHoogte() * VAKJE_GROOTTE);

        // Grid tekenen
        g.setColor(new Color(200, 200, 200));
        for (int y = 0; y < hotel.getHoogte(); y++) {
            for (int x = 0; x < hotel.getBreedte(); x++) {
                g.drawRect(x * VAKJE_GROOTTE, y * VAKJE_GROOTTE, VAKJE_GROOTTE, VAKJE_GROOTTE);
            }
        }

        // Areas tekenen
        List<Area> areas = hotel.getAreas();
        for (Area area : areas) {

            int x = (area.getX() - 1) * VAKJE_GROOTTE;
            int y = (area.getY() - 1) * VAKJE_GROOTTE;

            int breedte = area.getBreedte() * VAKJE_GROOTTE;
            int hoogte = area.getHoogte() * VAKJE_GROOTTE;

            // Achtergrond kleur
            g.setColor(getKleur(area));
            g.fillRect(x, y, breedte, hoogte);

            // Rand
            g.setColor(Color.DARK_GRAY);
            Graphics2D g2 = (Graphics2D) g;
            g2.setStroke(new BasicStroke(2));
            g.drawRect(x, y, breedte, hoogte);
            g2.setStroke(new BasicStroke(1));

            // Label
            g.setColor(Color.BLACK);
            g.setFont(new Font("Arial", Font.BOLD, 12));
            String label = getLabel(area);
            FontMetrics fm = g.getFontMetrics();

            int textX = x + (breedte - fm.stringWidth(label)) / 2;
            int textY = y + (hoogte + fm.getAscent()) / 2 - 2;

            g.drawString(label, textX, textY);
        }

        //  NIEUW: toon status (pause/active)
        if (!running) {
            g.setColor(new Color(0, 0, 0, 150));
            g.fillRect(0, 0, getWidth(), getHeight());

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            g.drawString("PAUSED", getWidth() / 2 - 70, getHeight() / 2);
        }
    }

    private String getLabel(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                return area.getClassification() != null ?
                        area.getClassification().replace(" Star", "★") : "Kamer";
            case "Cinema": return "Bioscoop";
            case "Restaurant": return "Restaurant";
            case "Fitness": return "Fitness";
            case "Lobby": return "Lobby";
            case "Lift": return "Lift";
            case "Staircase": return "Trap";
            case "Storage": return "Opslag";
            default: return area.getAreaType();
        }
    }

    private Color getKleur(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                String c = area.getClassification();
                if (c == null) return new Color(200, 230, 255);

                if (c.contains("1")) return new Color(200, 230, 255);
                if (c.contains("2")) return new Color(150, 200, 255);
                if (c.contains("3")) return new Color(100, 170, 255);
                if (c.contains("4")) return new Color(50, 130, 255);
                if (c.contains("5")) return new Color(0, 80, 200);

                return new Color(200, 230, 255);

            case "Lobby": return new Color(255, 220, 50);
            case "Lift": return new Color(255, 150, 0);
            case "Staircase": return new Color(100, 200, 100);
            case "Restaurant": return new Color(255, 100, 100);
            case "Cinema": return new Color(200, 100, 200);
            case "Fitness": return new Color(100, 220, 180);
            case "Storage": return new Color(180, 140, 100);
            default: return Color.WHITE;
        }
    }
}

package ui;

import model.Area;
import model.Hotel;
import model.Gast;
import model.Persoon;
import javax.swing.*;
import java.awt.*;
import java.util.List;

/**
 * Dit paneel is verantwoordelijk voor het visueel weergeven van het hotel.
 */
public class HotelPanel extends JPanel {

    private Hotel hotel;

    private final int VAKJE_GROOTTE = 50;

    //  NIEUW: status van simulatie (optioneel)
    private boolean running = true;

    public HotelPanel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
    }

    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
        repaint();
    }

    //  NIEUW: Simulator kan dit gebruiken
    public void setRunning(boolean running) {
        this.running = running;
    }

    private void updateDimensions() {
        if (hotel == null) return;

        int breedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        this.setPreferredSize(new Dimension(breedte, hoogte));
        revalidate(); //  belangrijk voor UI refresh
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        if (hotel == null) return;

        // Achtergrond (vloer)
        g.setColor(new Color(220, 220, 220));
        g.fillRect(0, 0, hotel.getBreedte() * VAKJE_GROOTTE, hotel.getHoogte() * VAKJE_GROOTTE);

        // Grid tekenen
        g.setColor(new Color(200, 200, 200));
        for (int y = 0; y < hotel.getHoogte(); y++) {
            for (int x = 0; x < hotel.getBreedte(); x++) {
                g.drawRect(x * VAKJE_GROOTTE, y * VAKJE_GROOTTE, VAKJE_GROOTTE, VAKJE_GROOTTE);
            }
        }

        // Areas tekenen
        List<Area> areas = hotel.getAreas();
        for (Area area : areas) {

            int x = (area.getX() - 1) * VAKJE_GROOTTE;
            int y = (area.getY() - 1) * VAKJE_GROOTTE;

            int breedte = area.getBreedte() * VAKJE_GROOTTE;
            int hoogte = area.getHoogte() * VAKJE_GROOTTE;

            // Achtergrond kleur
            g.setColor(getKleur(area));
            g.fillRect(x, y, breedte, hoogte);

            // Rand
            g.setColor(Color.DARK_GRAY);
            Graphics2D g2 = (Graphics2D) g;
            g2.setStroke(new BasicStroke(2));
            g.drawRect(x, y, breedte, hoogte);
            g2.setStroke(new BasicStroke(1));

            // Label
            g.setColor(Color.BLACK);
            g.setFont(new Font("Arial", Font.BOLD, 12));
            String label = getLabel(area);
            FontMetrics fm = g.getFontMetrics();

            int textX = x + (breedte - fm.stringWidth(label)) / 2;
            int textY = y + (hoogte + fm.getAscent()) / 2 - 2;

            g.drawString(label, textX, textY);
        }

        //  NIEUW: Teken alle personen
        for (Persoon persoon : hotel.getPersonen()) {
            if (persoon instanceof Gast) {
                Gast gast = (Gast) persoon;
                int px = gast.getX() * VAKJE_GROOTTE + VAKJE_GROOTTE / 2 - 8;
                int py = gast.getY() * VAKJE_GROOTTE + VAKJE_GROOTTE / 2 - 8;

                // Teken met gast's eigen kleur
                g.setColor(gast.getKleur());
                g.fillOval(px, py, 16, 16);

                // Teken rand (donkerder versie van dezelfde kleur)
                g.setColor(new Color(
                    Math.max(0, gast.getKleur().getRed() - 80),
                    Math.max(0, gast.getKleur().getGreen() - 80),
                    Math.max(0, gast.getKleur().getBlue() - 80)
                ));
                g.drawOval(px, py, 16, 16);

                // Teken naam als tooltip (optioneel, heel klein)
                g.setColor(Color.BLACK);
                g.setFont(new Font("Arial", Font.PLAIN, 8));
                g.drawString(gast.getNaam().substring(0, Math.min(3, gast.getNaam().length())), px + 2, py + 8);
            }
        }

        //  NIEUW: toon status (pause/active)
        if (!running) {
            g.setColor(new Color(0, 0, 0, 150));
            g.fillRect(0, 0, getWidth(), getHeight());

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            g.drawString("PAUSED", getWidth() / 2 - 70, getHeight() / 2);
        }
    }

    private String getLabel(Area area) {
        // ...existing code...
        switch (area.getAreaType()) {
            case "Room":
                return area.getClassification() != null ?
                        area.getClassification().replace(" Star", "★") : "Kamer";
            case "Cinema": return "Bioscoop";
            case "Restaurant": return "Restaurant";
            case "Fitness": return "Fitness";
            case "Lobby": return "Lobby";
            case "Lift": return "Lift";
            case "Staircase": return "Trap";
            case "Storage": return "Opslag";
            default: return area.getAreaType();
        }
    }

    private Color getKleur(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                String c = area.getClassification();
                if (c == null) return new Color(200, 230, 255);

                if (c.contains("1")) return new Color(200, 230, 255);
                if (c.contains("2")) return new Color(150, 200, 255);
                if (c.contains("3")) return new Color(100, 170, 255);
                if (c.contains("4")) return new Color(50, 130, 255);
                if (c.contains("5")) return new Color(0, 80, 200);

                return new Color(200, 230, 255);

            case "Lobby": return new Color(255, 220, 50);
            case "Lift": return new Color(255, 150, 0);
            case "Staircase": return new Color(100, 200, 100);
            case "Restaurant": return new Color(255, 100, 100);
            case "Cinema": return new Color(200, 100, 200);
            case "Fitness": return new Color(100, 220, 180);
            case "Storage": return new Color(180, 140, 100);
            default: return Color.WHITE;
        }
    }
}
